div.script:
(function(){
  var root = document.getElementById('mc-grid');
  if(!root) return;
  var deviceId = root.dataset.deviceId;
  var statusEl = document.getElementById('mc-status');
  var lastEl = document.getElementById('mc-last-read');
  var deviceEl = root;

  function pretty(v){ if(v===false || v===null || v===undefined) return '—'; return (typeof v === 'number') ? v.toFixed(4) : String(v); }

  function setAxis(axis, abs, rel, mac){
    var A = document.getElementById('abs-'+axis);
    var R = document.getElementById('rel-'+axis);
    var M = document.getElementById('mac-'+axis);
    if(A) A.textContent = pretty(abs);
    if(R) R.textContent = pretty(rel);
    if(M) M.textContent = pretty(mac);
  }

  function extractAndRender(payload){
    if(!payload || !payload.position || !payload.position.data) return;
    var list = payload.position.data;
    var names = ['x','y','z','a'];
    list.forEach(function(axis){
      var idx = axis.axis_index || 0;
      var name = names[idx] || 'x';
      var abs = (axis.absolute && axis.absolute.value!==undefined) ? axis.absolute.value : (axis.absolute && axis.absolute.raw!==undefined ? axis.absolute.raw : null);
      var rel = (axis.relative && axis.relative.value!==undefined) ? axis.relative.value : (axis.relative && axis.relative.raw!==undefined ? axis.relative.raw : null);
      var mac = (axis.machine && axis.machine.value!==undefined) ? axis.machine.value : (axis.machine && axis.machine.raw!==undefined ? axis.machine.raw : null);
      setAxis(name, abs, rel, mac);
    });
  }

  function fetchPos(refresh){
    var url = '/machine_control/api/position/' + deviceId + (refresh ? '?refresh=1' : '');
    fetch(url, {credentials: 'same-origin'})
      .then(function(r){ return r.json(); })
      .then(function(json){
        var st = json.status || json.result || 'unknown';
        statusEl.textContent = st.toUpperCase();
        statusEl.className = 'mc-status ' + (st === 'ok' ? 'ok' : (st === 'error' ? 'error' : ''));
        lastEl.textContent = json.last_read_at || '';
        var payload = json.payload || json;
        extractAndRender(payload);
      })
      .catch(function(e){
        statusEl.textContent = 'ERROR';
      });
  }

  // Jog controls
  function sendJog(axis, value){
    fetch('/machine_control/api/jog/' + deviceId, {
      method: 'POST',
      credentials: 'same-origin',
      headers: {'Content-Type': 'application/json'},
      body: JSON.stringify({axis: axis, value: value}),
    })
    .then(function(r){ return r.json(); })
    .then(function(j){ if(j.result !== 'ok') console.warn('jog error', j); else { console.log('jog ok', j, 'read_back=', j.read_back); if(j.candidates) console.warn('Direct jog symbols available:', j.candidates); } })
    .catch(function(e){ console.error('jog request failed', e); });
  }

  // Use long-polling: server holds connection until new data.
  var pollRetryDelay = 1000;

  function longpoll(last){
    var url = '/machine_control/api/longpoll/' + deviceId + (last ? '?last=' + encodeURIComponent(last) : '');
    fetch(url, {credentials: 'same-origin'})
      .then(function(r){ return r.json(); })
      .then(function(json){
        var st = json.status || json.result || 'unknown';
        statusEl.textContent = st.toUpperCase();
        statusEl.className = 'mc-status ' + (st === 'ok' ? 'ok' : (st === 'error' ? 'error' : ''));
        lastEl.textContent = json.last_read_at || '';
        var payload = json.payload || json;
        extractAndRender(payload);
        // Immediately re-establish longpoll with new last_read_at
        longpoll(json.last_read_at || '');
      })
      .catch(function(e){
        // Retry after delay on error
        console.error('longpoll error', e);
        setTimeout(function(){ longpoll(last); }, pollRetryDelay);
      });
  }

  // Start longpolling
  longpoll('');

  // Build jog UI
  (function buildJog(){
    var panel = document.createElement('div');
    panel.style.marginTop = '12px';
    panel.innerHTML = '<label style="margin-right:8px">Step:</label><input id="mc-jog-step" type="number" value="1" step="0.1" style="width:80px;margin-right:12px">';
    var axes = ['x','y','z','a'];
    axes.forEach(function(ax){
      var b1 = document.createElement('button');
      b1.textContent = ax.toUpperCase() + ' +';
      b1.style.marginRight = '6px';
      b1.onclick = function(){ var v = parseFloat(document.getElementById('mc-jog-step').value) || 0; sendJog(ax, v); };
      var b2 = document.createElement('button');
      b2.textContent = ax.toUpperCase() + ' -';
      b2.style.marginRight = '10px';
      b2.onclick = function(){ var v = -(parseFloat(document.getElementById('mc-jog-step').value) || 0); sendJog(ax, v); };
      panel.appendChild(b1);
      panel.appendChild(b2);
    });
    root.parentNode.insertBefore(panel, root.nextSibling);
  })();

  // Keep snapshot polling at a low frequency for persistent storage
  setInterval(function(){
    fetch('/machine_control/api/snapshot/' + deviceId, {credentials: 'same-origin'})
      .then(function(r){ return r.json(); })
      .then(function(j){ console.log('snapshot', j); })
      .catch(console.error);
  }, 60000);
})();
